const row = $json;
let domain = null;

// 1. First priority: Check if cleanedDomain has data
if (row.cleanedDomain && row.cleanedDomain.trim() !== "") {
    domain = row.cleanedDomain.trim().toLowerCase();
} 

// 2. Second priority: If domain is still missing, extract from website
else if (row.website && row.website.trim() !== "") {
    // Verified Split Logic for n8n
    let clean = row.website.replace('http://', '').replace('https://', '');
    clean = clean.replace('www.', '');
    domain = clean.split('/')[0].toLowerCase();
}

return {
    ...row,
    extractedDomain: domain,
    domainError: domain ? null : "No domain or website found"
};

for (const item of $input.all()) {
  let html = item.json.data; // This is the raw HTML from HTTP Request

  if (!html) {
    item.json.cleanedText = "";
    continue;
  }

  // 1️⃣ Remove script and style blocks
  html = html.replace(/<script[\s\S]*?<\/script>/gi, '');
  html = html.replace(/<style[\s\S]*?<\/style>/gi, '');

  // 2️⃣ Remove JSON blobs inside <script type="application/json"> (like Wix viewer model)
  html = html.replace(/<script[^>]*type=["']application\/json["'][\s\S]*?<\/script>/gi, '');

  // 3️⃣ Remove comments
  html = html.replace(/<!--[\s\S]*?-->/g, '');

  // 4️⃣ Remove all remaining HTML tags
  let text = html.replace(/<[^>]+>/g, ' ');

  // 5️⃣ Decode common HTML entities
  text = text.replace(/&nbsp;/g, ' ');
  text = text.replace(/&amp;/g, '&');
  text = text.replace(/&quot;/g, '"');
  text = text.replace(/&lt;/g, '<');
  text = text.replace(/&gt;/g, '>');

  // 6️⃣ Collapse whitespace and trim
  text = text.replace(/\s+/g, ' ').trim();

  // 7️⃣ Limit length to ~5000 chars for AI efficiency
  item.json.cleanedText = text.slice(0, 5000);
}

// This uses the correct n8n syntax to return your cleaned data
return $input.all().map(item => {
  return {
    json: {
      cleanedText: item.json.cleanedText,
      status: "ready_for_ai_analysis",
      length: item.json.cleanedText.length
    }
  };
});

